class Solution:
    def xorAfterQueries(self, nums, queries):
        MOD = 10**9 + 7
        arr = list(nums)
        for q in queries:
            l, r, k, v = q[0], q[1], q[2], q[3]
            positions = []
            idx = l
            while idx <= r:
                positions.append(idx)
                idx += k
            for p in positions:
                arr[p] = (arr[p] * v) % MOD
        x = 0
        for a in arr:
            x ^= a
        return x

