var xorAfterQueries = function(nums, queries) {
    const MOD = 1000000007n;
    const arr = nums.map(BigInt);
    for (const [l, r, k, v] of queries) {
        const bv = BigInt(v);
        for (let idx = l; idx <= r; idx += k) {
            arr[idx] = (arr[idx] * bv) % MOD;
        }
    }
    let res = 0n;
    for (const a of arr) res ^= a;
    return Number(res);
};
